+	"github.com/prometheus/prometheus/config"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const transactionalReloadStateFilename = "transactional-reload-state.json"
+
+type transactionalReloader struct {
+	mu       sync.RWMutex
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+	path     string
+}
+
+func newTransactionalReloader(dir string, logger *slog.Logger) *transactionalReloader {
+	t := &transactionalReloader{path: filepath.Join(dir, transactionalReloadStateFilename)}
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			logger.Warn("Unable to read transactional reload state", "err", err)
+		}
+		return t
+	}
+	if err := json.Unmarshal(b, &t.status); err != nil {
+		logger.Warn("Unable to parse transactional reload state", "err", err)
+		t.status = api_v1.ReloadStatus{}
+	}
+	return t
+}
+
+func (t *transactionalReloader) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	s := t.status
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]float64, len(t.status.ReloaderTimingsMS))
+	for k, v := range t.status.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+func (t *transactionalReloader) setLastGood(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.lastGood = conf
+}
+
+func (t *transactionalReloader) persist(logger *slog.Logger) {
+	t.mu.RLock()
+	b, err := json.Marshal(t.status)
+	t.mu.RUnlock()
+	if err != nil {
+		logger.Warn("Unable to marshal transactional reload state", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(t.path), 0o755); err != nil {
+		logger.Warn("Unable to create transactional reload state directory", "err", err)
+		return
+	}
+	tmp := t.path + ".tmp"
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		logger.Warn("Unable to write transactional reload state", "err", err)
+		return
+	}
+	if err := os.Rename(tmp, t.path); err != nil {
+		logger.Warn("Unable to persist transactional reload state", "err", err)
+	}
+}
+
+func (t *transactionalReloader) record(status api_v1.ReloadStatus, logger *slog.Logger) {
+	t.mu.Lock()
+	t.status = status
+	t.mu.Unlock()
+	t.persist(logger)
+}
+
+func (t *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	start := time.Now()
+	status := api_v1.ReloadStatus{
+		LastReloadID:      start.UTC().Format(time.RFC3339),
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		t.record(status, logger)
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+		if len(status.AppliedReloaders) == 0 {
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+		}
+
+		status.RollbackAttempted = true
+		rollbackErr := t.rollback(logger, rls)
+		status.RollbackSuccessful = rollbackErr == nil
+		if rollbackErr != nil {
+			status.ErrorCategory = "rollback_error"
+			status.ErrorMessage = fmt.Sprintf("apply failed: %v; rollback failed: %v", err, rollbackErr)
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, rollbackErr)
+		}
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+
+	t.setLastGood(conf)
+	status.LastReloadSuccessful = true
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
+
+func (t *transactionalReloader) rollback(logger *slog.Logger, rls []reloader) error {
+	t.mu.RLock()
+	conf := t.lastGood
+	t.mu.RUnlock()
+	if conf == nil {
+		return fmt.Errorf("no known-good configuration is available")
+	}
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			logger.Error("Failed to roll back configuration", "reloader", rl.name, "err", err)
+			return fmt.Errorf("reloader %q: %w", rl.name, err)
+		}
+	}
+	return nil
+}
